// // This module outputs LOW when any two of the first three inputs are HIGH, or when the fourth input is LOW and the fifth input is HIGH.
module top_module(
    input in1,
    input in2,
    input in3,
    input in4,
    input in5,
    output out
);assign out = (in1 & in2 & in3) | (in4 & ~in5);

endmodule
